diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..87e655de1611 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2862,7 +2862,82 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {

   return nullptr;
 }
-
+static Instruction *foldSelectSelect(SelectInst &SI, InstCombinerImpl &IC) {
+  Value *Cond = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+  // Canonicalize not condition by swapping true/false arms.
+  Value *NotCond;
+  if (match(Cond, m_Not(m_Value(NotCond)))) {
+    Cond = NotCond;
+    std::swap(TrueVal, FalseVal);
+  }
+  Value *C, *D;
+  // Check condition: select C, D, false  or  select C, true, D
+  bool IsAndPattern = match(Cond, m_Select(m_Value(C), m_Value(D), m_Zero()));
+  bool IsOrPattern = false;
+  if (!IsAndPattern) {
+    if (match(Cond, m_Select(m_Value(C), m_One(), m_Value(D)))) {
+      IsOrPattern = true;
+    } else {
+      return nullptr;
+    }
+  }
+  // Check if one of the arms is a select with same condition C (or its negation).
+  SelectInst *InnerSel = dyn_cast<SelectInst>(TrueVal);
+  bool IsTrueArm = true;
+  if (!InnerSel) {
+    InnerSel = dyn_cast<SelectInst>(FalseVal);
+    IsTrueArm = false;
+  }
+  if (!InnerSel)
+    return nullptr;
+  Value *InnerCond = InnerSel->getCondition();
+  // Determine if InnerCond is C or not C.
+  bool InnerCondIsNotC = false;
+  if (match(InnerCond, m_Not(m_Specific(C)))) {
+    InnerCondIsNotC = true;
+  } else if (InnerCond != C) {
+    return nullptr;
+  }
+  // Normalize inner select to condition C by swapping true/false values if needed.
+  Value *A = InnerSel->getTrueValue();
+  Value *B = InnerSel->getFalseValue();
+  if (InnerCondIsNotC) {
+    // select not C, A, B  == select C, B, A
+    std::swap(A, B);
+  }
+  // Now inner select is equivalent to select C, A, B.
+  Value *X = IsTrueArm ? FalseVal : TrueVal; // the other value (non-select)
+  auto &Builder = IC.Builder;
+  Value *InnerSelect;
+  if (IsAndPattern) {
+    if (IsTrueArm) {
+      // (C && D) ? (C ? A : B) : X  -> C ? (D ? A : X) : X
+      InnerSelect = Builder.CreateSelect(D, A, X);
+      Value *OuterSelect = Builder.CreateSelect(C, InnerSelect, X);
+      return IC.replaceInstUsesWith(SI, OuterSelect);
+    } else {
+      // (C && D) ? X : (C ? A : B)  -> C ? (D ? X : A) : B
+      InnerSelect = Builder.CreateSelect(D, X, A);
+      Value *OuterSelect = Builder.CreateSelect(C, InnerSelect, B);
+      return IC.replaceInstUsesWith(SI, OuterSelect);
+    }
+  } else {
+    // IsOrPattern: select C, true, D  (C || D)
+    if (IsTrueArm) {
+      // (C || D) ? (C ? A : B) : X  -> C ? A : (D ? B : X)
+      InnerSelect = Builder.CreateSelect(D, B, X);
+      Value *OuterSelect = Builder.CreateSelect(C, A, InnerSelect);
+      return IC.replaceInstUsesWith(SI, OuterSelect);
+    } else {
+      // (C || D) ? X : (C ? A : B)  -> C ? X : (D ? X : B)
+      InnerSelect = Builder.CreateSelect(D, X, B);
+      Value *OuterSelect = Builder.CreateSelect(C, X, InnerSelect);
+      return IC.replaceInstUsesWith(SI, OuterSelect);
+    }
+  }
+}
 Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -2920,6 +2995,8 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {

   if (Instruction *R = foldSelectOfBools(SI))
     return R;
+  if (Instruction *R = foldSelectSelect(SI, *this))
+    return R;

   // Selecting between two integer or vector splat integer constants?
   //

